  // ── Guide ──────────────────────────────────────────────────────────────────
  guide_title: { ar: "دليل استخدام سماد الديدان", en: "Worm Fertilizer Usage Guide", fr: "Guide d'utilisation de l'engrais de vers" },
  guide_sub: { ar: "كيف تستفيد من سماد الديدان بأقصى قدر ممكن؟", en: "How to get the most out of worm fertilizer?", fr: "Comment tirer le meilleur parti de l'engrais de vers ?" },
  guide_step1_title: { ar: "حدّد الكمية المناسبة", en: "Determine the Right Quantity", fr: "Déterminer la bonne quantité" },
  guide_step1_body: { ar: "للنباتات المنزلية: ملعقتان كبيرتان لكل أصيص. للخضروات: حفنة (≈ 100 غ) لكل شتلة. للأشجار المثمرة: 2–3 كلغ حول قاعدة الشجرة.", en: "Houseplants: 2 tablespoons per pot. Vegetables: a handful (≈ 100g) per seedling. Fruit trees: 2–3 kg around the base of the tree.", fr: "Plantes d'intérieur : 2 cuillères à soupe par pot. Légumes : une poignée (≈ 100g) par plant. Arbres fruitiers : 2–3 kg autour de la base de l'arbre." },
  guide_step2_title: { ar: "اخلطه مع التربة", en: "Mix with Soil", fr: "Mélanger avec la terre" },
  guide_step2_body: { ar: "اخلط السماد مع التربة السطحية (5–10 سم الأولى) قبل الزراعة، أو ضعه حول النبات بعد الزراعة دون أن يلامس الجذور مباشرة.", en: "Mix the fertilizer with the topsoil (first 5–10 cm) before planting, or place it around the plant after planting without directly touching the roots.", fr: "Mélangez l'engrais avec la couche supérieure du sol (5–10 cm) avant la plantation, ou placez-le autour de la plante après la plantation sans toucher directement les racines." },
  guide_step3_title: { ar: "اسقِ بانتظام", en: "Water Regularly", fr: "Arroser régulièrement" },
  guide_step3_body: { ar: "بعد التطبيق، اسقِ النبات جيداً لتنشيط الميكروبات النافعة. حافظ على رطوبة معتدلة طوال الموسم.", en: "After application, water the plant well to activate beneficial microbes. Maintain moderate moisture throughout the season.", fr: "Après l'application, arrosez bien la plante pour activer les microbes bénéfiques. Maintenir une humidité modérée tout au long de la saison." },
  guide_step4_title: { ar: "كرّر كل 30–45 يوماً", en: "Repeat Every 30–45 Days", fr: "Répéter toutes les 30–45 jours" },
  guide_step4_body: { ar: "سماد الديدان بطيء الإطلاق وآمن، يمكن إعادة تطبيقه كل شهر إلى شهر ونصف خلال موسم النمو دون خطر الإفراط.", en: "Worm compost is slow-release and safe, can be reapplied every month to a month and a half during the growing season without risk of excess.", fr: "Le compost de vers est à libération lente et sûr, peut être réappliqué toutes les 4 à 6 semaines pendant la saison de croissance sans risque d'excès." },
  guide_tea_title: { ar: "شاي الديدان (سماد سائل)", en: "Worm Tea (Liquid Fertilizer)", fr: "Thé de vers (engrais liquide)" },
  guide_tea_step1: { ar: "خفّف 50 مل من شاي الديدان في 1 لتر ماء.", en: "Dilute 50 ml of worm tea in 1 liter of water.", fr: "Diluez 50 ml de thé de vers dans 1 litre d'eau." },
  guide_tea_step2: { ar: "اسقِ التربة عند الجذور أو رشّ الأوراق في الصباح الباكر أو المساء.", en: "Water the soil at the roots or spray the leaves early in the morning or in the evening.", fr: "Arrosez le sol aux racines ou pulvérisez les feuilles tôt le matin ou le soir." },
  guide_tea_step3: { ar: "كرّر كل 10–14 يوماً للنباتات الضعيفة أو الشتلات.", en: "Repeat every 10–14 days for weak plants or seedlings.", fr: "Répétez toutes les 10 à 14 jours pour les plantes faibles ou les semis." },
  guide_dosage_title: { ar: "جدول الجرعات حسب النوع", en: "Dosage Table by Type", fr: "Tableau de dosage par type" },
  guide_crop_fruit: { ar: "الأشجار المثمرة", en: "Fruit Trees", fr: "Arbres fruitiers" },
  guide_crop_ornamental: { ar: "النباتات الزينة", en: "Ornamental Plants", fr: "Plantes ornementales" },
  guide_crop_leafy: { ar: "الخضروات الورقية", en: "Leafy Vegetables", fr: "Légumes feuillus" },
  guide_crop_field: { ar: "محاصيل حقلية", en: "Field Crops", fr: "Cultures de plein champ" },
  guide_dose_fruit: { ar: "2–3 كلغ حول الجذع", en: "2–3 kg around the trunk", fr: "2–3 kg autour du tronc" },
  guide_dose_ornamental: { ar: "ملعقتان لكل أصيص", en: "2 tablespoons per pot", fr: "2 cuillères à soupe par pot" },
  guide_dose_leafy: { ar: "100 غ لكل متر مربع", en: "100g per square meter", fr: "100g par mètre carré" },
  guide_dose_field: { ar: "500 كلغ لكل هكتار", en: "500 kg per hectare", fr: "500 kg par hectare" },
